`/lib/tax/types.ts` - Shared tax types:
```typescript
export type FilingStatus = 'single' | 'married';
export type USState = 'WA' | 'CA' | 'NY' | 'TX';

export interface TaxBracket {
  upperLimit: number; // Infinity for highest bracket
  rate: number; // 0.10 for 10%
}

export interface TaxBreakdown {
  bracket: string; // "$11,600 - $47,150"
  rate: number; // 0.12
  taxableInBracket: number; // Amount taxed in this bracket
  tax: number; // Tax from this bracket
}

export interface TaxResult {
  tax: number;
  effectiveRate: number;
  marginalRate: number;
  breakdown: TaxBreakdown[];
}

export interface StateTaxResult {
  tax: number;
  effectiveRate: number;
  breakdown: string; // Human-readable explanation
}
```

`/lib/tax/us-calculator.ts` - Core implementation:
```typescript
import type { FilingStatus, USState, TaxResult, StateTaxResult, TaxBracket } from './types';

const FEDERAL_BRACKETS_2025: Record<FilingStatus, TaxBracket[]> = {
  single: [
    { upperLimit: 11600, rate: 0.10 },
    { upperLimit: 47150, rate: 0.12 },
    { upperLimit: 100525, rate: 0.22 },
    { upperLimit: 191950, rate: 0.24 },
    { upperLimit: 243725, rate: 0.32 },
    { upperLimit: 609350, rate: 0.35 },
    { upperLimit: Infinity, rate: 0.37 }
  ],
  married: [
    { upperLimit: 23200, rate: 0.10 },
    { upperLimit: 94300, rate: 0.12 },
    { upperLimit: 201050, rate: 0.22 },
    { upperLimit: 383900, rate: 0.24 },
    { upperLimit: 487450, rate: 0.32 },
    { upperLimit: 731200, rate: 0.35 },
    { upperLimit: Infinity, rate: 0.37 }
  ]
};

const STANDARD_DEDUCTION_2025: Record<FilingStatus, number> = {
  single: 14600,
  married: 29200
};

const CA_BRACKETS_2025: TaxBracket[] = [
  { upperLimit: 10412, rate: 0.01 },
  { upperLimit: 24684, rate: 0.02 },
  { upperLimit: 38959, rate: 0.04 },
  { upperLimit: 54081, rate: 0.06 },
  { upperLimit: 68350, rate: 0.08 },
  { upperLimit: 349137, rate: 0.093 },
  { upperLimit: 418961, rate: 0.103 },
  { upperLimit: 698271, rate: 0.113 },
  { upperLimit: Infinity, rate: 0.123 }
];

const NY_BRACKETS_2025: TaxBracket[] = [
  { upperLimit: 8500, rate: 0.04 },
  { upperLimit: 11700, rate: 0.045 },
  { upperLimit: 13900, rate: 0.0525 },
  { upperLimit: 80650, rate: 0.0585 },
  { upperLimit: 215400, rate: 0.0625 },
  { upperLimit: 1077550, rate: 0.0685 },
  { upperLimit: 5000000, rate: 0.0965 },
  { upperLimit: 25000000, rate: 0.103 },
  { upperLimit: Infinity, rate: 0.109 }
];

function calculateTaxFromBrackets(income: number, brackets: TaxBracket[]): { tax: number; breakdown: TaxBreakdown[]; marginalRate: number } {
  let tax = 0;
  let previousLimit = 0;
  const breakdown: TaxBreakdown[] = [];
  let marginalRate = 0;

  for (const bracket of brackets) {
    if (income <= previousLimit) break;

    const taxableInBracket = Math.min(income, bracket.upperLimit) - previousLimit;
    const taxFromBracket = taxableInBracket * bracket.rate;
    tax += taxFromBracket;
    marginalRate = bracket.rate;

    breakdown.push({
      bracket: `$${previousLimit.toLocaleString()} - $${bracket.upperLimit === Infinity ? '∞' : bracket.upperLimit.toLocaleString()}`,
      rate: bracket.rate,
      taxableInBracket,
      tax: taxFromBracket
    });

    previousLimit = bracket.upperLimit;
  }

  return { tax, breakdown, marginalRate };
}

export function calculateUSFederalTax(income: number, filingStatus: FilingStatus): TaxResult {
  const deduction = STANDARD_DEDUCTION_2025[filingStatus];
  const taxableIncome = Math.max(0, income - deduction);
  const brackets = FEDERAL_BRACKETS_2025[filingStatus];

  const { tax, breakdown, marginalRate } = calculateTaxFromBrackets(taxableIncome, brackets);
  const effectiveRate = income > 0 ? tax / income : 0;

  return { tax, effectiveRate, marginalRate, breakdown };
}

export function calculateUSStateTax(income: number, state: USState): StateTaxResult {
  if (state === 'WA' || state === 'TX') {
    return { tax: 0, effectiveRate: 0, breakdown: `${state} has no state income tax` };
  }

  const stateConfigs = {
    CA: { brackets: CA_BRACKETS_2025, deduction: 5363 },
    NY: { brackets: NY_BRACKETS_2025, deduction: 8000 }
  };

  const config = stateConfigs[state];
  const taxableIncome = Math.max(0, income - config.deduction);
  const { tax } = calculateTaxFromBrackets(taxableIncome, config.brackets);
  const effectiveRate = income > 0 ? tax / income : 0;

  return {
    tax,
    effectiveRate,
    breakdown: `${state} state tax on $${income.toLocaleString()} (deduction: $${config.deduction.toLocaleString()}) = $${tax.toFixed(2)}`
  };
}

/**
 * Article XV proration: Only US-sourced income is taxable by US
 * For workers who moved to Canada mid-vesting period, prorate by physical presence
 * @param totalIncome Full RSU income
 * @param usDays Days physically present in US during vesting period
 * @param totalDays Total days in vesting period (typically 365 for annual vest)
 */
export function prorateIncome(totalIncome: number, usDays: number, totalDays: number): number {
  if (totalDays === 0) return 0;
  return (totalIncome * usDays) / totalDays;
}
```

