```typescript
import { describe, it, expect } from 'vitest';
import { calculateUSFederalTax, calculateUSStateTax, prorateIncome } from '../us-calculator';

describe('US Federal Tax Calculator', () => {
  it('calculates federal tax for single filer with $100k income', () => {
    const result = calculateUSFederalTax(100000, 'single');
    expect(result.tax).toBeGreaterThanOrEqual(14210); // Within $50 of $14,260
    expect(result.tax).toBeLessThanOrEqual(14310);
    expect(result.effectiveRate).toBeCloseTo(0.143, 2);
    expect(result.marginalRate).toBe(0.22);
    expect(result.breakdown.length).toBeGreaterThan(0);
  });

  it('applies standard deduction correctly for married filing', () => {
    const result = calculateUSFederalTax(200000, 'married');
    expect(result.tax).toBeGreaterThanOrEqual(24500);
    expect(result.tax).toBeLessThanOrEqual(25000);
  });

  it('handles edge case: income below standard deduction', () => {
    const result = calculateUSFederalTax(10000, 'single');
    expect(result.tax).toBe(0);
  });
});

describe('US State Tax Calculator', () => {
  it('calculates CA state tax for $100k income', () => {
    const result = calculateUSStateTax(100000, 'CA');
    expect(result.tax).toBeGreaterThanOrEqual(4150);
    expect(result.tax).toBeLessThanOrEqual(4250);
    expect(result.breakdown).toContain('CA state tax');
  });

  it('calculates NY state tax for $100k income', () => {
    const result = calculateUSStateTax(100000, 'NY');
    expect(result.tax).toBeGreaterThanOrEqual(4750);
    expect(result.tax).toBeLessThanOrEqual(4850);
  });

  it('returns zero for WA (no income tax)', () => {
    const result = calculateUSStateTax(100000, 'WA');
    expect(result.tax).toBe(0);
    expect(result.breakdown).toContain('no state income tax');
  });

  it('returns zero for TX (no income tax)', () => {
    const result = calculateUSStateTax(100000, 'TX');
    expect(result.tax).toBe(0);
  });
});

describe('Article XV Income Proration', () => {
  it('prorates income for partial year US resident', () => {
    const prorated = prorateIncome(100000, 180, 365);
    expect(prorated).toBeCloseTo(49315, 0);
  });

  it('returns full income if present all 365 days', () => {
    const prorated = prorateIncome(100000, 365, 365);
    expect(prorated).toBe(100000);
  });

  it('returns zero if zero days in US', () => {
    const prorated = prorateIncome(100000, 0, 365);
    expect(prorated).toBe(0);
  });
});
```

**Acceptance Criteria:**
1. Run `npm test` → all 11 tests pass
2. Single filer, $100k income, WA state: Federal tax $14,210-$14,310, state $0, effective rate 14.2-14.3%
3. Single filer, $100k income, CA state: Federal $14,210-$14,310, state $4,150-$4,250, total $18,360-$18,560
4. Single filer, $100k income, NY state: Federal $14,210-$14,310, state $4,750-$4,850
5. Married filer, $200k income: Federal $24,500-$25,000 (lower effective rate than single $100k)
6. Proration: $100k RSU, 180/365 days = $49,315 US-sourced income
7. Edge cases: Income below deduction = $0 tax, zero days in US = $0 US-sourced
8. Run `npm run test:ui` opens Vitest UI in browser showing all test results

