`/lib/tax/canada-calculator.ts` - Core implementation:
```typescript
import type { TaxResult, TaxBracket, TaxBreakdown } from './types';

export type CanadaProvince = 'BC' | 'ON' | 'AB';

const FEDERAL_BRACKETS_2025: TaxBracket[] = [
  { upperLimit: 55867, rate: 0.15 },
  { upperLimit: 111733, rate: 0.205 },
  { upperLimit: 173205, rate: 0.26 },
  { upperLimit: 246752, rate: 0.29 },
  { upperLimit: Infinity, rate: 0.33 }
];

const BASIC_PERSONAL_AMOUNT = 15705;

const PROVINCIAL_CONFIGS = {
  BC: {
    brackets: [
      { upperLimit: 47937, rate: 0.0506 },
      { upperLimit: 95875, rate: 0.077 },
      { upperLimit: 110076, rate: 0.105 },
      { upperLimit: 133664, rate: 0.1229 },
      { upperLimit: 181232, rate: 0.147 },
      { upperLimit: 252752, rate: 0.168 },
      { upperLimit: Infinity, rate: 0.205 }
    ],
    basicAmount: 12580
  },
  ON: {
    brackets: [
      { upperLimit: 51446, rate: 0.0505 },
      { upperLimit: 102894, rate: 0.0915 },
      { upperLimit: 150000, rate: 0.1116 },
      { upperLimit: 220000, rate: 0.1216 },
      { upperLimit: Infinity, rate: 0.1316 }
    ],
    basicAmount: 11865
  },
  AB: {
    brackets: [
      { upperLimit: Infinity, rate: 0.10 }
    ],
    basicAmount: 21885
  }
};

function calculateTaxFromBrackets(income: number, brackets: TaxBracket[]): { tax: number; breakdown: TaxBreakdown[]; marginalRate: number } {
  let tax = 0;
  let previousLimit = 0;
  const breakdown: TaxBreakdown[] = [];
  let marginalRate = 0;

  for (const bracket of brackets) {
    if (income <= previousLimit) break;

    const taxableInBracket = Math.min(income, bracket.upperLimit) - previousLimit;
    const taxFromBracket = taxableInBracket * bracket.rate;
    tax += taxFromBracket;
    marginalRate = bracket.rate;

    breakdown.push({
      bracket: `$${previousLimit.toLocaleString()} - $${bracket.upperLimit === Infinity ? '∞' : bracket.upperLimit.toLocaleString()}`,
      rate: bracket.rate,
      taxableInBracket,
      tax: taxFromBracket
    });

    previousLimit = bracket.upperLimit;
  }

  return { tax, breakdown, marginalRate };
}

export function calculateCanadaFederalTax(income: number): TaxResult {
  const taxableIncome = Math.max(0, income - BASIC_PERSONAL_AMOUNT);
  const { tax, breakdown, marginalRate } = calculateTaxFromBrackets(taxableIncome, FEDERAL_BRACKETS_2025);
  const effectiveRate = income > 0 ? tax / income : 0;

  return { tax, effectiveRate, marginalRate, breakdown };
}

export function calculateCanadaProvincialTax(income: number, province: CanadaProvince): TaxResult {
  const config = PROVINCIAL_CONFIGS[province];
  const taxableIncome = Math.max(0, income - config.basicAmount);
  const { tax, breakdown, marginalRate } = calculateTaxFromBrackets(taxableIncome, config.brackets);
  const effectiveRate = income > 0 ? tax / income : 0;

  return { tax, effectiveRate, marginalRate, breakdown };
}

export interface ForeignTaxCreditResult {
  ftcAmount: number;
  remainingCanadaTax: number;
  explanation: string;
  excessUSCredit: number; // Amount of US tax that cannot be credited
}

/**
 * Calculate Foreign Tax Credit (FTC) per Article XV of US-Canada tax treaty
 * Canada allows credit for US tax paid on US-sourced income, but limited to:
 * - Amount of US tax actually paid
 * - Canada's tax rate applied to the US-sourced income
 * 
 * Formula: FTC = min(US tax paid, Canada tax on total × (US-sourced income / total income))
 * 
 * @param usTaxPaid Total US tax paid (federal + state)
 * @param usSourcedIncome Income earned while in US (prorated by Article XV)
 * @param totalIncome Total worldwide income for Canadian tax purposes
 * @param canadaTaxOnTotal Total Canadian tax before FTC (federal + provincial)
 */
export function calculateForeignTaxCredit(
  usTaxPaid: number,
  usSourcedIncome: number,
  totalIncome: number,
  canadaTaxOnTotal: number
): ForeignTaxCreditResult {
  if (totalIncome === 0 || usSourcedIncome === 0) {
    return {
      ftcAmount: 0,
      remainingCanadaTax: canadaTaxOnTotal,
      explanation: 'No US-sourced income to credit',
      excessUSCredit: usTaxPaid
    };
  }

  // Canada's effective tax on the US-sourced portion
  const canadaTaxOnUSPortion = canadaTaxOnTotal * (usSourcedIncome / totalIncome);

  // FTC is limited to the lesser of:
  // 1. US tax actually paid
  // 2. Canada's tax on the US-sourced portion
  const ftcAmount = Math.min(usTaxPaid, canadaTaxOnUSPortion);
  const remainingCanadaTax = Math.max(0, canadaTaxOnTotal - ftcAmount);
  const excessUSCredit = Math.max(0, usTaxPaid - canadaTaxOnUSPortion);

  const explanation = `US tax paid: $${usTaxPaid.toFixed(2)}. Canada's tax on US-sourced portion ($${usSourcedIncome.toFixed(2)} / $${totalIncome.toFixed(2)} × $${canadaTaxOnTotal.toFixed(2)}) = $${canadaTaxOnUSPortion.toFixed(2)}. FTC: $${ftcAmount.toFixed(2)}${excessUSCredit > 0 ? `. Excess US credit not recoverable: $${excessUSCredit.toFixed(2)}` : ''}`;

  return { ftcAmount, remainingCanadaTax, explanation, excessUSCredit };
}
```

