`/app/api/rsu/[id]/route.ts` - GET handler with full tax calculation:
```typescript
import { NextRequest, NextResponse } from 'next/server';
import db from '@/lib/db/init';
import { calculateUSFederalTax, calculateUSStateTax } from '@/lib/tax/us-calculator';
import { calculateCanadaFederalTax, calculateCanadaProvincialTax, calculateForeignTaxCredit } from '@/lib/tax/canada-calculator';
import { getUSDCADRate, convertUSDToCAD } from '@/lib/currency';
import type { USState } from '@/lib/tax/types';
import type { CanadaProvince } from '@/lib/tax/canada-calculator';

export async function GET(
  req: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const rsu = db.prepare('SELECT * FROM rsu_events WHERE id = ?').get(params.id) as any;

    if (!rsu) {
      return NextResponse.json({ error: 'RSU event not found' }, { status: 404 });
    }

    const exchangeRate = await getUSDCADRate();
    const totalValueCAD = convertUSDToCAD(rsu.total_value_usd, exchangeRate);

    // Calculate US taxes (assuming 100% US-sourced for H-1B/TN workers still in US)
    const usFederal = calculateUSFederalTax(rsu.total_value_usd, 'single');
    const usState = calculateUSStateTax(rsu.total_value_usd, rsu.us_state as USState);
    const totalUSTax = usFederal.tax + usState.tax;

    // Calculate Canada taxes on CAD-converted income
    const canadaFederal = calculateCanadaFederalTax(totalValueCAD);
    const canadaProvincial = calculateCanadaProvincialTax(totalValueCAD, rsu.canada_province as CanadaProvince);
    const totalCanadaTax = canadaFederal.tax + canadaProvincial.tax;

    // Calculate Foreign Tax Credit
    const ftc = calculateForeignTaxCredit(
      totalUSTax,
      rsu.total_value_usd, // 100% US-sourced for MVP
      totalValueCAD,
      totalCanadaTax
    );

    return NextResponse.json({
      rsu: {
        id: rsu.id,
        employer: rsu.employer,
        tickerSymbol: rsu.ticker_symbol,
        vestingDate: rsu.vesting_date,
        shares: rsu.shares,
        fmvUsd: rsu.fmv_usd,
        totalValueUsd: rsu.total_value_usd,
        totalValueCad: totalValueCAD,
        usState: rsu.us_state,
        canadaProvince: rsu.canada_province
      },
      usTax: {
        federal: usFederal,
        state: usState,
        total: totalUSTax,
        effectiveRate: totalUSTax / rsu.total_value_usd
      },
      canadaTax: {
        federal: canadaFederal,
        provincial: canadaProvincial,
        totalBeforeFTC: totalCanadaTax,
        ftc,
        netTotal: ftc.remainingCanadaTax,
        effectiveRate: ftc.remainingCanadaTax / totalValueCAD
      },
      exchangeRate
    });
  } catch (error) {
    console.error('Error calculating RSU taxes:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
```

