   ```typescript
   type BoCAPIResponse = {
     observations: Array<{
       d: string;
       FXUSDCAD: { v: string };
     }>;
   };

   export async function getExchangeRate(date: string): Promise<number> {
     // 1. Check cache
     const cached = db.prepare('SELECT rate, fetched_at FROM exchange_rates WHERE date = ?').get(date);
     const now = Date.now();
     if (cached && (now - cached.fetched_at < 24 * 60 * 60 * 1000)) {
       return cached.rate;
     }

     // 2. Fetch from BoC API
     try {
       const response = await fetch(
         `https://www.bankofcanada.ca/valet/observations/FXUSDCAD/json?start_date=${date}&end_date=${date}`,
         { next: { revalidate: 86400 } } // Next.js cache for 24h
       );
       if (!response.ok) throw new Error('BoC API error');
       const data: BoCAPIResponse = await response.json();
       const rate = parseFloat(data.observations[0]?.FXUSDCAD?.v);
       if (!rate || isNaN(rate)) throw new Error('Invalid rate');

       // 3. Cache in DB
       db.prepare('INSERT OR REPLACE INTO exchange_rates (date, rate, fetched_at) VALUES (?, ?, ?)').run(date, rate, now);
       return rate;
     } catch (error) {
       // 4. Fallback strategy
       console.error('BoC API fetch failed:', error);
       if (cached) return cached.rate; // Use stale cache
       const fallbackYear = parseInt(date.split('-')[0]);
       return STATIC_RATES[fallbackYear] || 1.35; // Ultimate fallback
     }
   }

   export async function convertUsdToCadByDate(amount: number, date: string): Promise<number> {
     const rate = await getExchangeRate(date);
     return amount * rate;
   }
   ```
