   'use server';
   import { revalidatePath } from 'next/cache';
   import { db } from '@/lib/db/client';

   export async function toggleFormCompletion(userId: number, formCode: string) {
     const current = db.prepare('SELECT completed FROM form_completion WHERE user_id = ? AND form_code = ?').get(userId, formCode);
     const newState = current ? !current.completed : true;
     const now = newState ? Date.now() : null;

     db.prepare(`
       INSERT INTO form_completion (user_id, form_code, completed, completed_at)
       VALUES (?, ?, ?, ?)
       ON CONFLICT (user_id, form_code) DO UPDATE SET
         completed = excluded.completed,
         completed_at = excluded.completed_at
     `).run(userId, formCode, newState ? 1 : 0, now);

     revalidatePath('/forms-checklist');
     return newState;
   }
   ```
