   'use client';
   import * as Accordion from '@radix-ui/react-accordion';
   import { FormItem } from './form-item';
   import { toggleFormCompletion } from '@/app/actions/forms';

   export function FormsChecklist({ forms, completionStatus, userId }) {
     const [optimisticState, setOptimisticState] = useState(completionStatus);

     const handleToggle = async (formCode: string) => {
       setOptimisticState(prev => ({ ...prev, [formCode]: !prev[formCode] }));
       await toggleFormCompletion(userId, formCode);
