       <Accordion.Root type='multiple' className='space-y-4'>
         {forms.map(form => (
           <FormItem
             key={form.code}
             form={form}
             completed={optimisticState[form.code] || false}
             onToggle={() => handleToggle(form.code)}
           />
         ))}
       </Accordion.Root>
     );
