   function getDeadlineBadgeColor(deadline: string): string {
     const today = new Date();
     const [month, day] = deadline.split('/').map(Number);
     const deadlineDate = new Date(today.getFullYear(), month - 1, day);
     const daysUntil = Math.ceil((deadlineDate - today) / (1000 * 60 * 60 * 24));

     if (daysUntil < 0) return 'bg-red-100 text-red-800'; // Past due
     if (daysUntil <= 30) return 'bg-yellow-100 text-yellow-800'; // Within 30 days
     return 'bg-blue-100 text-blue-800'; // Future
