```typescript
'use client';
import { calculateFTC, FTCInput, FTCResult } from '@/lib/tax/ftc-calculator';
import { TaxComparisonChart } from './tax-comparison-chart';
import { FilingStrategyCard } from './filing-strategy-card';

interface FTCOptimizerProps {
  rsuEntry: {
    id: string;
    grossIncome: number;
    vestingDate: string;
    employer: string;
  };
  usTax: { federal: number; state: number };
  canadaTax: { federal: number; provincial: number };
  workAllocation: { daysInCanada: number; totalDays: number };
  state: string;
  province: string;
}

export function FTCOptimizer(props: FTCOptimizerProps) {
  const ftcInput: FTCInput = {
    grossIncome: props.rsuEntry.grossIncome,
    usFederalTax: props.usTax.federal,
    usStateTax: props.usTax.state,
    canadaFederalTax: props.canadaTax.federal,
    canadaProvincialTax: props.canadaTax.provincial,
    workDaysInCanada: props.workAllocation.daysInCanada,
    totalWorkDays: props.workAllocation.totalDays,
    state: props.state,
    province: props.province,
  };

  const ftcResult = calculateFTC(ftcInput);

  return (
    <section className="space-y-6">
      <h2 className="text-2xl font-bold">Foreign Tax Credit Analysis</h2>

      {/* Before/After comparison */}
      <TaxComparisonChart 
        beforeFTC={ftcResult.totalTaxWithoutFTC}
        afterFTC={ftcResult.totalTaxWithFTC}
        usTax={props.usTax.federal + props.usTax.state}
        canadaTax={props.canadaTax.federal + props.canadaTax.provincial}
        ftcSavings={ftcResult.savings}
      />

      {/* Strategy recommendation */}
      <FilingStrategyCard 
        strategy={ftcResult.optimalStrategy}
        ftcAmount={ftcResult.optimalStrategy === 'file-us-first' ? ftcResult.usFTC : ftcResult.canadaFTC}
        details={ftcResult.details}
      />

      {/* Collapsible explanation */}
      <details className="bg-blue-50 rounded-xl p-6">
        <summary className="cursor-pointer font-semibold">How does Article XV work?</summary>
        <p className="mt-4 text-sm text-gray-700">
          Under the US-Canada Tax Treaty Article XV, employment income (including RSU vesting) is sourced based on where you performed the work. If you worked {props.workAllocation.daysInCanada}/{props.workAllocation.totalDays} days in Canada, that portion is considered Canadian-source income for US tax purposes. This allows you to claim a Foreign Tax Credit in the US for Canadian taxes paid on that income, preventing double taxation.
        </p>
      </details>
    </section>
  );
}
```

