import { NextRequest, NextResponse } from 'next/server';
import { getRSUById } from '@/lib/db/queries'; // Assuming this exists
import { generateTaxSummaryPDF } from '@/lib/pdf/tax-summary-generator';

export async function GET(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const rsuEntry = await getRSUById(params.id);
    if (!rsuEntry) {
      return NextResponse.json({ error: 'RSU not found' }, { status: 404 });
    }

    // Generate PDF buffer
    const pdfBuffer = await generateTaxSummaryPDF(rsuEntry);

    // Return PDF with download headers
    return new NextResponse(pdfBuffer, {
      status: 200,
      headers: {
        'Content-Type': 'application/pdf',
        'Content-Disposition': `attachment; filename="taxbridge-summary-${params.id}.pdf"`,
        'Content-Length': pdfBuffer.length.toString(),
      },
    });
  } catch (error) {
    console.error('PDF generation error:', error);
    return NextResponse.json({ error: 'PDF generation failed' }, { status: 500 });
  }
}
```

2. **PDF Generator** (/lib/pdf/tax-summary-generator.ts):
```typescript
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { calculateFTC } from '@/lib/tax/ftc-calculator';
import { calculateUSTax, calculateCanadaTax } from '@/lib/tax/calculators'; // Assuming these exist

export async function generateTaxSummaryPDF(rsuEntry: any): Promise<Buffer> {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4',
  });

  let yPosition = 20;

  // HEADER (lines 20-40)
  doc.setFontSize(24);
  doc.setTextColor(30, 64, 175); // Blue-700
  doc.text('TaxBridge Tax Summary', 105, yPosition, { align: 'center' });
  yPosition += 15;
  doc.setFontSize(10);
  doc.setTextColor(100, 100, 100);
  doc.text(`Generated: ${new Date().toLocaleDateString('en-US')}`, 105, yPosition, { align: 'center' });
  yPosition += 15;

  // SECTION 1: RSU Details (lines 45-75)
  doc.setFontSize(14);
  doc.setTextColor(0, 0, 0);
  doc.text('RSU Details', 20, yPosition);
  yPosition += 8;

  autoTable(doc, {
    startY: yPosition,
    head: [['Field', 'Value']],
    body: [
      ['Vesting Date', new Date(rsuEntry.vestingDate).toLocaleDateString()],
      ['Employer', rsuEntry.employer],
      ['Shares Vested', rsuEntry.shares.toLocaleString()],
      ['Fair Market Value (USD)', `$${rsuEntry.fmvUSD.toFixed(2)}`],
      ['Total Value (USD)', `$${(rsuEntry.shares * rsuEntry.fmvUSD).toLocaleString()}`],
      ['Total Value (CAD)', `$${(rsuEntry.shares * rsuEntry.fmvUSD * rsuEntry.exchangeRate).toLocaleString()} CAD`],
    ],
    headStyles: { fillColor: [30, 64, 175] },
    margin: { left: 20, right: 20 },
  });
  yPosition = (doc as any).lastAutoTable.finalY + 10;

  // SECTION 2: Tax Breakdown (lines 80-120)
  const usTax = calculateUSTax(rsuEntry);
  const canadaTax = calculateCanadaTax(rsuEntry);
  const ftcResult = calculateFTC({
    grossIncome: rsuEntry.shares * rsuEntry.fmvUSD,
    usFederalTax: usTax.federal,
    usStateTax: usTax.state,
    canadaFederalTax: canadaTax.federal,
    canadaProvincialTax: canadaTax.provincial,
    workDaysInCanada: 260,
    totalWorkDays: 260,
    state: rsuEntry.state,
    province: rsuEntry.province,
  });

  doc.text('Dual-Country Tax Breakdown', 20, yPosition);
  yPosition += 8;

  autoTable(doc, {
    startY: yPosition,
    head: [['Jurisdiction', 'Tax Type', 'Amount']],
    body: [
      ['United States', 'Federal Tax', `$${usTax.federal.toLocaleString()}`],
      ['United States', `${rsuEntry.state} State Tax`, `$${usTax.state.toLocaleString()}`],
      ['Canada', 'Federal Tax', `$${canadaTax.federal.toLocaleString()}`],
      ['Canada', `${rsuEntry.province} Provincial Tax`, `$${canadaTax.provincial.toLocaleString()}`],
      ['', 'Total (before FTC)', `$${ftcResult.totalTaxWithoutFTC.toLocaleString()}`],
    ],
    headStyles: { fillColor: [30, 64, 175] },
    margin: { left: 20, right: 20 },
  });
  yPosition = (doc as any).lastAutoTable.finalY + 10;

  // SECTION 3: FTC Calculation (lines 125-165)
  doc.text('Foreign Tax Credit Analysis', 20, yPosition);
  yPosition += 8;

  autoTable(doc, {
    startY: yPosition,
    body: [
      ['Filing Strategy', ftcResult.optimalStrategy === 'file-us-first' ? 'File US First' : 'File Canada First'],
      ['Foreign Tax Credit', `$${(ftcResult.optimalStrategy === 'file-us-first' ? ftcResult.usFTC : ftcResult.canadaFTC).toLocaleString()}`],
      ['Total Tax After FTC', `$${ftcResult.totalTaxWithFTC.toLocaleString()}`],
      ['Tax Savings', `$${ftcResult.savings.toLocaleString()} (${(ftcResult.savings / ftcResult.totalTaxWithoutFTC * 100).toFixed(1)}%)`],
    ],
    headStyles: { fillColor: [34, 197, 94] }, // Green for savings
    margin: { left: 20, right: 20 },
  });
  yPosition = (doc as any).lastAutoTable.finalY + 10;

  // SECTION 4: Net Tax Liability (lines 170-190)
  doc.setFontSize(16);
  doc.setTextColor(34, 197, 94); // Green
  doc.text(`Net Tax Liability: $${ftcResult.totalTaxWithFTC.toLocaleString()}`, 105, yPosition, { align: 'center' });
  yPosition += 15;

  // SECTION 5: Required Forms Checklist (lines 195-240)
  doc.setFontSize(14);
  doc.setTextColor(0, 0, 0);
  doc.text('Required Tax Forms', 20, yPosition);
  yPosition += 8;

  const forms = [
    { form: 'W-2', description: 'Wage and Tax Statement (from employer)', country: 'US' },
    { form: '1040 / 1040-NR', description: 'US Individual Income Tax Return', country: 'US' },
    { form: 'Form 1116', description: 'Foreign Tax Credit (if filing US first)', country: 'US' },
    { form: 'Form 8833', description: 'Treaty-Based Return Position (Article XV)', country: 'US' },
    { form: 'T1', description: 'Canadian Income Tax Return', country: 'Canada' },
    { form: 'T4', description: 'Statement of Remuneration Paid (from employer)', country: 'Canada' },
    { form: 'T2209', description: 'Federal Foreign Tax Credits', country: 'Canada' },
    { form: 'FBAR (FinCEN 114)', description: 'Foreign Bank Account Report (if CAD accounts > $10k)', country: 'US' },
    { form: 'Form 8938', description: 'Foreign Financial Assets (if total > threshold)', country: 'US' },
  ];

  autoTable(doc, {
    startY: yPosition,
    head: [['☐', 'Form', 'Description', 'Country']],
    body: forms.map(f => ['☐', f.form, f.description, f.country]),
    headStyles: { fillColor: [30, 64, 175] },
    margin: { left: 20, right: 20 },
    columnStyles: { 0: { cellWidth: 8 } },
  });
  yPosition = (doc as any).lastAutoTable.finalY + 15;

  // FOOTER (lines 245-260)
  doc.setFontSize(8);
  doc.setTextColor(150, 150, 150);
  const disclaimer = 'This summary is for informational purposes only and does not constitute tax advice. Consult a qualified tax professional for your specific situation.';
  doc.text(disclaimer, 105, 280, { align: 'center', maxWidth: 170 });

  // Convert to buffer
  const pdfOutput = doc.output('arraybuffer');
  return Buffer.from(pdfOutput);
}
```

