```typescript
'use client';
import { useState } from 'react';
import { ArrowDownTrayIcon } from '@heroicons/react/24/outline'; // Or lucide-react

interface ExportButtonProps {
  rsuId: string;
  variant?: 'primary' | 'icon';
}

export function ExportButton({ rsuId, variant = 'primary' }: ExportButtonProps) {
  const [loading, setLoading] = useState(false);

  const handleExport = async () => {
    setLoading(true);
    try {
      const response = await fetch(`/api/export/${rsuId}`);
      if (!response.ok) throw new Error('Export failed');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `taxbridge-summary-${rsuId}.pdf`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Export error:', error);
      alert('Failed to generate PDF. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  if (variant === 'icon') {
    return (
      <button
        onClick={handleExport}
        disabled={loading}
        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition disabled:opacity-50"
        title="Export PDF"
      >
        {loading ? '...' : <ArrowDownTrayIcon className="w-5 h-5" />}
      </button>
    );
  }

  return (
    <button
      onClick={handleExport}
      disabled={loading}
      className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg transition disabled:opacity-50 flex items-center gap-2"
    >
      <ArrowDownTrayIcon className="w-5 h-5" />
      {loading ? 'Generating...' : 'Export PDF'}
    </button>
  );
}
