3. `/app/api/stripe/webhook/route.ts`:
```ts
import { stripe } from '@/lib/stripe';
import { headers } from 'next/headers';
export async function POST(req: Request) {
  const body = await req.text();
  const sig = headers().get('stripe-signature')!;
  const event = stripe.webhooks.constructEvent(body, sig, process.env.STRIPE_WEBHOOK_SECRET!);

  if (event.type === 'checkout.session.completed') {
    const session = event.data.object;
    const clerkUserId = session.metadata.clerk_user_id;
    const tier = session.metadata.tier;
    db.prepare('UPDATE user_profiles SET subscription_tier = ?, stripe_customer_id = ? WHERE clerk_user_id = ?')
      .run(tier, session.customer, clerkUserId);
  }
  if (event.type === 'customer.subscription.deleted') {
    const subscription = event.data.object;
    db.prepare('UPDATE user_profiles SET subscription_tier = "free" WHERE stripe_customer_id = ?')
      .run(subscription.customer);
  }
  return Response.json({ received: true });
}
```

